examples.before:
File file = new File("/tmp/data.csv");
file.delete();
file.createNewFile();
// Return values ignored — deletion or creation failure goes unnoticed

examples.after:
File file = new File("/tmp/data.csv");
if (!file.delete()) {
  throw new IOException("Failed to delete " + file.getAbsolutePath());
}
if (!file.createNewFile()) {
  throw new IOException("Failed to create " + file.getAbsolutePath());
}

